mapper.select:
SELECT id, register_id, doctor_id, role, content, tool_calls_json, created_at
FROM (
    SELECT *
    FROM physician_ai_chat_history
    WHERE register_id = #{registerId}
    ORDER BY created_at DESC
    LIMIT #{limit}
) recent
ORDER BY created_at ASC

